378 // Return the number of iterations to peel off from the beginning and end of the
379 // loop respectively, that make conditions in the body true/false. For example,
380 // if we peel 2 iterations off the loop below, the condition i < 2 can be
381 // evaluated at compile time.
382 //
383 //  for (i = 0; i < n; i++)
384 //    if (i < 2)
385 //      ..
386 //    else
387 //      ..
388 //   }
389 static std::pair<unsigned, unsigned>
390 countToEliminateCompares(Loop &L, unsigned MaxPeelCount, ScalarEvolution &SE) {
391   assert(L.isLoopSimplifyForm() && "Loop needs to be in loop simplify form");
392   unsigned DesiredPeelCount = 0;
393   unsigned DesiredPeelCountLast = 0;
394 
395   // Do not peel the entire loop.
396   const SCEV *BE = SE.getConstantMaxBackedgeTakenCount(&L);
397   if (const SCEVConstant *SC = dyn_cast<SCEVConstant>(BE))
398     MaxPeelCount =
399         std::min((unsigned)SC->getAPInt().getLimitedValue() - 1, MaxPeelCount);
400 
401   // Increase PeelCount while (IterVal Pred BoundSCEV) condition is satisfied;
402   // return true if inversed condition become known before reaching the
403   // MaxPeelCount limit.
404   auto PeelWhilePredicateIsKnown =
405       [&](unsigned &PeelCount, const SCEV *&IterVal, const SCEV *BoundSCEV,
406           const SCEV *Step, ICmpInst::Predicate Pred) {
407         while (PeelCount < MaxPeelCount &&
408                SE.isKnownPredicate(Pred, IterVal, BoundSCEV)) {
409           IterVal = SE.getAddExpr(IterVal, Step);
410           ++PeelCount;
411         }
412         return SE.isKnownPredicate(ICmpInst::getInversePredicate(Pred), IterVal,
413                                    BoundSCEV);
414       };
415 
416   const unsigned MaxDepth = 4;
417   std::function<void(Value *, unsigned)> ComputePeelCount =
418       [&](Value *Condition, unsigned Depth) -> void {
419     if (!Condition->getType()->isIntegerTy() || Depth >= MaxDepth)
420       return;
421 
422     Value *LeftVal, *RightVal;
423     if (match(Condition, m_And(m_Value(LeftVal), m_Value(RightVal))) ||
424         match(Condition, m_Or(m_Value(LeftVal), m_Value(RightVal)))) {
425       ComputePeelCount(LeftVal, Depth + 1);
426       ComputePeelCount(RightVal, Depth + 1);
427       return;
428     }
429 
430     CmpPredicate Pred;
431     if (!match(Condition, m_ICmp(Pred, m_Value(LeftVal), m_Value(RightVal))))
432       return;
433 
434     const SCEV *LeftSCEV = SE.getSCEV(LeftVal);
435     const SCEV *RightSCEV = SE.getSCEV(RightVal);
436 
437     // Do not consider predicates that are known to be true or false
438     // independently of the loop iteration.
439     if (SE.evaluatePredicate(Pred, LeftSCEV, RightSCEV))
440       return;
441 
442     // Check if we have a condition with one AddRec and one non AddRec
443     // expression. Normalize LeftSCEV to be the AddRec.
444     if (!isa<SCEVAddRecExpr>(LeftSCEV)) {
445       if (isa<SCEVAddRecExpr>(RightSCEV)) {
446         std::swap(LeftSCEV, RightSCEV);
447         Pred = ICmpInst::getSwappedPredicate(Pred);
448       } else
449         return;
450     }
451 
452     const SCEVAddRecExpr *LeftAR = cast<SCEVAddRecExpr>(LeftSCEV);
453 
454     // Avoid huge SCEV computations in the loop below, make sure we only
455     // consider AddRecs of the loop we are trying to peel.
456     if (!LeftAR->isAffine() || LeftAR->getLoop() != &L)
457       return;
458     if (!(ICmpInst::isEquality(Pred) && LeftAR->hasNoSelfWrap()) &&
459         !SE.getMonotonicPredicateType(LeftAR, Pred))
460       return;
461 
462     // Check if extending the current DesiredPeelCount lets us evaluate Pred
463     // or !Pred in the loop body statically.
464     unsigned NewPeelCount = DesiredPeelCount;
465 
466     const SCEV *IterVal = LeftAR->evaluateAtIteration(
467         SE.getConstant(LeftSCEV->getType(), NewPeelCount), SE);
468 
469     // If the original condition is not known, get the negated predicate
470     // (which holds on the else branch) and check if it is known. This allows
471     // us to peel of iterations that make the original condition false.
472     if (!SE.isKnownPredicate(Pred, IterVal, RightSCEV))
473       Pred = ICmpInst::getInversePredicate(Pred);
474 
475     const SCEV *Step = LeftAR->getStepRecurrence(SE);
476     if (!PeelWhilePredicateIsKnown(NewPeelCount, IterVal, RightSCEV, Step,
477                                    Pred)) {
478       if (shouldPeelLastIteration(L, Pred, LeftAR, RightSCEV, SE))
479         DesiredPeelCountLast = 1;
480       return;
481     }
482 
483     // However, for equality comparisons, that isn't always sufficient to
484     // eliminate the comparsion in loop body, we may need to peel one more
485     // iteration. See if that makes !Pred become unknown again.
486     const SCEV *NextIterVal = SE.getAddExpr(IterVal, Step);
487     if (ICmpInst::isEquality(Pred) &&
488         !SE.isKnownPredicate(ICmpInst::getInversePredicate(Pred), NextIterVal,
489                              RightSCEV) &&
490         !SE.isKnownPredicate(Pred, IterVal, RightSCEV) &&
491         SE.isKnownPredicate(Pred, NextIterVal, RightSCEV)) {
492       if (NewPeelCount >= MaxPeelCount)
493         return; // Need to peel one more iteration, but can't. Give up.
494       ++NewPeelCount; // Great!
495     }
496 
497     DesiredPeelCount = std::max(DesiredPeelCount, NewPeelCount);
498     DesiredPeelCountLast = std::max(DesiredPeelCountLast, NewPeelCount);
499   };
