580   SmallVector<BasicBlock *, 4> ExitBlocks;
581   L->getUniqueNonLatchExitBlocks(ExitBlocks);
582   return any_of(ExitBlocks, [](const BasicBlock *EB) {
583       return !EB->getTerminatingDeoptimizeCall();
584     });
