 878   // The new header is hooked up directly to the "top", which is either
 879   // the original loop preheader (for the first iteration) or the previous
 880   // iteration's exiting block (for every other iteration)
 881   InsertTop->getTerminator()->setSuccessor(0, cast<BasicBlock>(VMap[Header]));
 882 
 883   // Similarly, for the latch:
 884   // The original exiting edge is still hooked up to the loop exit.
 885   BasicBlock *NewLatch = cast<BasicBlock>(VMap[Latch]);
 886   if (PeelLast) {
 887     // This is the last iteration and we definitely will go to the exit. Just
 888     // set both successors to InsertBot and let the branch be simplified later.
 889     assert(IterNumber == 0 && "Only peeling a single iteration implemented.");
 890     auto *LatchTerm = cast<BranchInst>(NewLatch->getTerminator());
 891     LatchTerm->setSuccessor(0, InsertBot);
 892     LatchTerm->setSuccessor(1, InsertBot);
 893   } else {
 894     auto *LatchTerm = cast<Instruction>(NewLatch->getTerminator());
 895     // The backedge now goes to the "bottom", which is either the loop's real
 896     // header (for the last peeled iteration) or the copied header of the next
 897     // iteration (for every other iteration)
 898     for (unsigned idx = 0, e = LatchTerm->getNumSuccessors(); idx < e; ++idx) {
 899       if (LatchTerm->getSuccessor(idx) == Header) {
 900         LatchTerm->setSuccessor(idx, InsertBot);
 901         break;
 902       }
 903     }
 904   }
 905   if (DT)
 906     DT->changeImmediateDominator(InsertBot, NewLatch);
 907 
 908   // The new copy of the loop body starts with a bunch of PHI nodes
 909   // that pick an incoming value from either the preheader, or the previous
 910   // loop iteration. Since this copy is no longer part of the loop, we
 911   // resolve this statically:
 912   if (PeelLast) {
 913     // For the last iteration, we use the value from the latch of the original
 914     // loop directly.
 915     for (BasicBlock::iterator I = Header->begin(); isa<PHINode>(I); ++I) {
 916       PHINode *NewPHI = cast<PHINode>(VMap[&*I]);
 917       VMap[&*I] = NewPHI->getIncomingValueForBlock(Latch);
 918       NewPHI->eraseFromParent();
 919     }
 920   } else {
 921     // For the first iteration, we use the value from the preheader directly.
 922     // For any other iteration, we replace the phi with the value generated by
 923     // the immediately preceding clone of the loop body (which represents
 924     // the previous iteration).
 925     for (BasicBlock::iterator I = Header->begin(); isa<PHINode>(I); ++I) {
 926       PHINode *NewPHI = cast<PHINode>(VMap[&*I]);
 927       if (IterNumber == 0) {
 928         VMap[&*I] = NewPHI->getIncomingValueForBlock(PreHeader);
 929       } else {
 930         Value *LatchVal = NewPHI->getIncomingValueForBlock(Latch);
 931         Instruction *LatchInst = dyn_cast<Instruction>(LatchVal);
 932         if (LatchInst && L->contains(LatchInst))
 933           VMap[&*I] = LVMap[LatchInst];
 934         else
 935           VMap[&*I] = LatchVal;
 936       }
 937       NewPHI->eraseFromParent();
 938     }
 939   }
 940 
 941   // Fix up the outgoing values - we need to add a value for the iteration
 942   // we've just created. Note that this must happen *after* the incoming
 943   // values are adjusted, since the value going out of the latch may also be
 944   // a value coming into the header.
 945   for (auto Edge : ExitEdges)
 946     for (PHINode &PHI : Edge.second->phis()) {
 947       Value *LatchVal = PHI.getIncomingValueForBlock(Edge.first);
 948       Instruction *LatchInst = dyn_cast<Instruction>(LatchVal);
 949       if (LatchInst && L->contains(LatchInst))
 950         LatchVal = VMap[LatchVal];
 951       PHI.addIncoming(LatchVal, cast<BasicBlock>(VMap[Edge.first]));
 952       SE.forgetLcssaPhiWithNewPredecessor(L, &PHI);
 953     }
 954 
 955   // LastValueMap is updated with the values for the current loop
 956   // which are used the next time this function is called.
 957   for (auto KV : VMap)
 958     LVMap[KV.first] = KV.second;
 959 }
