1000 /// Note that this does not peel them off as a single straight-line block.
1001 /// Rather, each iteration is peeled off separately, and needs to check the
1002 /// exit condition.
1003 /// For loops that dynamically execute \p PeelCount iterations or less
1004 /// this provides a benefit, since the peeled off iterations, which account
1005 /// for the bulk of dynamic execution, can be further simplified by scalar
1006 /// optimizations.
1007 bool llvm::peelLoop(Loop *L, unsigned PeelCount, bool PeelLast, LoopInfo *LI,
1008                     ScalarEvolution *SE, DominatorTree &DT, AssumptionCache *AC,
1009                     bool PreserveLCSSA, ValueToValueMapTy &LVMap) {
1010   assert(PeelCount > 0 && "Attempt to peel out zero iterations?");
1011   assert(canPeel(L) && "Attempt to peel a loop which is not peelable?");
1012   assert((!PeelLast || (canPeelLastIteration(*L, *SE) && PeelCount == 1)) &&
1013          "when peeling the last iteration, the loop must be supported and can "
1014          "only peel a single iteration");
1015 
1016   LoopBlocksDFS LoopBlocks(L);
1017   LoopBlocks.perform(LI);
1018 
1019   BasicBlock *Header = L->getHeader();
1020   BasicBlock *PreHeader = L->getLoopPreheader();
1021   BasicBlock *Latch = L->getLoopLatch();
1022   SmallVector<std::pair<BasicBlock *, BasicBlock *>, 4> ExitEdges;
1023   L->getExitEdges(ExitEdges);
1024 
1025   // Remember dominators of blocks we might reach through exits to change them
1026   // later. Immediate dominator of such block might change, because we add more
1027   // routes which can lead to the exit: we can reach it from the peeled
1028   // iterations too.
1029   DenseMap<BasicBlock *, BasicBlock *> NonLoopBlocksIDom;
1030   for (auto *BB : L->blocks()) {
1031     auto *BBDomNode = DT.getNode(BB);
1032     SmallVector<BasicBlock *, 16> ChildrenToUpdate;
1033     for (auto *ChildDomNode : BBDomNode->children()) {
1034       auto *ChildBB = ChildDomNode->getBlock();
1035       if (!L->contains(ChildBB))
1036         ChildrenToUpdate.push_back(ChildBB);
1037     }
1038     // The new idom of the block will be the nearest common dominator
1039     // of all copies of the previous idom. This is equivalent to the
1040     // nearest common dominator of the previous idom and the first latch,
1041     // which dominates all copies of the previous idom.
1042     BasicBlock *NewIDom = DT.findNearestCommonDominator(BB, Latch);
1043     for (auto *ChildBB : ChildrenToUpdate)
1044       NonLoopBlocksIDom[ChildBB] = NewIDom;
1045   }
1046 
1047   Function *F = Header->getParent();
1048 
1049   // Set up all the necessary basic blocks.
1050   BasicBlock *InsertTop;
1051   BasicBlock *InsertBot;
1052   BasicBlock *NewPreHeader;
1053   DenseMap<Instruction *, Value *> ExitValues;
1054   if (PeelLast) {
1055     // It is convenient to split the single exit block from the latch the
1056     // into 3 parts - two blocks to anchor the peeled copy of the loop body,
1057     // and a new final  exit block.
1058 
1059     // Peeling the last iteration transforms.
1060     //
1061     // PreHeader:
1062     // ...
1063     // Header:
1064     //   LoopBody
1065     //   If (cond) goto Header
1066     // Exit:
1067     //
1068     // into
1069     //
1070     // Header:
1071     //  LoopBody
1072     //  If (cond) goto Header
1073     // InsertTop:
1074     //   LoopBody
1075     //   If (!cond) goto InsertBot
1076     // InsertBot:
1077     // Exit:
1078     // ...
1079     BasicBlock *Exit = L->getExitBlock();
1080     for (PHINode &P : Exit->phis())
1081       ExitValues[&P] = P.getIncomingValueForBlock(Latch);
1082 
1083     InsertTop = SplitEdge(Latch, Exit, &DT, LI);
1084     InsertBot = SplitBlock(InsertTop, InsertTop->getTerminator(), &DT, LI);
1085 
1086     InsertTop->setName(Exit->getName() + ".peel.begin");
1087     InsertBot->setName(Exit->getName() + ".peel.next");
1088   } else {
1089     // It is convenient to split the preheader into 3 parts - two blocks to
1090     // anchor the peeled copy of the loop body, and a new preheader for the
1091     // "real" loop.
1092 
1093     // Peeling the first iteration transforms.
1094     //
1095     // PreHeader:
1096     // ...
1097     // Header:
1098     //   LoopBody
1099     //   If (cond) goto Header
1100     // Exit:
1101     //
1102     // into
1103     //
1104     // InsertTop:
1105     //   LoopBody
1106     //   If (!cond) goto Exit
1107     // InsertBot:
1108     // NewPreHeader:
1109     // ...
1110     // Header:
1111     //  LoopBody
1112     //  If (cond) goto Header
1113     // Exit:
1114     //
1115     // Each following iteration will split the current bottom anchor in two,
1116     // and put the new copy of the loop body between these two blocks. That
1117     // is, after peeling another iteration from the example above, we'll
1118     // split InsertBot, and get:
1119     //
1120     // InsertTop:
1121     //   LoopBody
1122     //   If (!cond) goto Exit
1123     // InsertBot:
1124     //   LoopBody
1125     //   If (!cond) goto Exit
1126     // InsertBot.next:
1127     // NewPreHeader:
1128     // ...
1129     // Header:
1130     //  LoopBody
1131     //  If (cond) goto Header
1132     // Exit:
1133     //
1134     InsertTop = SplitEdge(PreHeader, Header, &DT, LI);
1135     InsertBot = SplitBlock(InsertTop, InsertTop->getTerminator(), &DT, LI);
1136     NewPreHeader = SplitBlock(InsertBot, InsertBot->getTerminator(), &DT, LI);
1137 
1138     InsertTop->setName(Header->getName() + ".peel.begin");
1139     InsertBot->setName(Header->getName() + ".peel.next");
1140     NewPreHeader->setName(PreHeader->getName() + ".peel.newph");
1141   }
1142 
1143   Instruction *LatchTerm =
1144       cast<Instruction>(cast<BasicBlock>(Latch)->getTerminator());
1145 
1146   // If we have branch weight information, we'll want to update it for the
1147   // newly created branches.
1148   DenseMap<Instruction *, WeightInfo> Weights;
1149   initBranchWeights(Weights, L);
1150 
1151   // Identify what noalias metadata is inside the loop: if it is inside the
1152   // loop, the associated metadata must be cloned for each iteration.
1153   SmallVector<MDNode *, 6> LoopLocalNoAliasDeclScopes;
1154   identifyNoAliasScopesToClone(L->getBlocks(), LoopLocalNoAliasDeclScopes);
1155 
1156   // For each peeled-off iteration, make a copy of the loop.
1157   ValueToValueMapTy VMap;
1158   for (unsigned Iter = 0; Iter < PeelCount; ++Iter) {
1159     SmallVector<BasicBlock *, 8> NewBlocks;
1160 
1161     cloneLoopBlocks(L, Iter, PeelLast, InsertTop, InsertBot, ExitEdges,
1162                     NewBlocks, LoopBlocks, VMap, LVMap, &DT, LI,
1163                     LoopLocalNoAliasDeclScopes, *SE);
1164 
1165     // Remap to use values from the current iteration instead of the
1166     // previous one.
1167     remapInstructionsInBlocks(NewBlocks, VMap);
1168 
1169     if (Iter == 0) {
1170       if (PeelLast) {
1171         // Adjust the exit condition so the loop exits one iteration early.
1172         // For now we simply subtract one form the second operand of the
1173         // exit condition. This relies on the peel count computation to
1174         // check that this is actually legal. In particular, it ensures that
1175         // the first operand of the compare is an AddRec with step 1 and we
1176         // execute more than one iteration.
1177         auto *Cmp =
1178             cast<ICmpInst>(L->getLoopLatch()->getTerminator()->getOperand(0));
1179         IRBuilder B(Cmp);
1180         Cmp->setOperand(
1181             1, B.CreateSub(Cmp->getOperand(1),
1182                            ConstantInt::get(Cmp->getOperand(1)->getType(), 1)));
1183       } else {
1184         // Update IDoms of the blocks reachable through exits.
1185         for (auto BBIDom : NonLoopBlocksIDom)
1186           DT.changeImmediateDominator(BBIDom.first,
1187                                       cast<BasicBlock>(LVMap[BBIDom.second]));
1188       }
1189     }
1190 
1191 #ifdef EXPENSIVE_CHECKS
1192     assert(DT.verify(DominatorTree::VerificationLevel::Fast));
1193 #endif
1194 
1195     for (auto &[Term, Info] : Weights) {
1196       auto *TermCopy = cast<Instruction>(VMap[Term]);
1197       updateBranchWeights(TermCopy, Info);
1198     }
1199 
1200     // Remove Loop metadata from the latch branch instruction
1201     // because it is not the Loop's latch branch anymore.
1202     auto *LatchTermCopy = cast<Instruction>(VMap[LatchTerm]);
1203     LatchTermCopy->setMetadata(LLVMContext::MD_loop, nullptr);
1204 
1205     InsertTop = InsertBot;
1206     InsertBot = SplitBlock(InsertBot, InsertBot->getTerminator(), &DT, LI);
1207     InsertBot->setName(Header->getName() + ".peel.next");
1208 
1209     F->splice(InsertTop->getIterator(), F, NewBlocks[0]->getIterator(),
1210               F->end());
1211   }
1212 
1213   if (PeelLast) {
1214     // Now adjust users of the original exit values by replacing them with the
1215     // exit value from the peeled iteration.
1216     for (const auto &[P, E] : ExitValues)
1217       P->replaceAllUsesWith(VMap.lookup(E));
1218     formLCSSA(*L, DT, LI, SE);
1219   } else {
1220     // Now adjust the phi nodes in the loop header to get their initial values
1221     // from the last peeled-off iteration instead of the preheader.
1222     for (BasicBlock::iterator I = Header->begin(); isa<PHINode>(I); ++I) {
1223       PHINode *PHI = cast<PHINode>(I);
1224       Value *NewVal = PHI->getIncomingValueForBlock(Latch);
1225       Instruction *LatchInst = dyn_cast<Instruction>(NewVal);
1226       if (LatchInst && L->contains(LatchInst))
1227         NewVal = LVMap[LatchInst];
1228 
1229       PHI->setIncomingValueForBlock(NewPreHeader, NewVal);
1230     }
1231   }
1232 
1233   for (const auto &[Term, Info] : Weights) {
1234     setBranchWeights(*Term, Info.Weights, /*IsExpected=*/false);
1235   }
1236 
1237   // Update Metadata for count of peeled off iterations.
1238   unsigned AlreadyPeeled = 0;
1239   if (auto Peeled = getOptionalIntLoopAttribute(L, PeeledCountMetaData))
1240     AlreadyPeeled = *Peeled;
1241   addStringMetadataToLoop(L, PeeledCountMetaData, AlreadyPeeled + PeelCount);
1242 
1243   if (Loop *ParentLoop = L->getParentLoop())
1244     L = ParentLoop;
1245 
1246   // We modified the loop, update SE.
1247   SE->forgetTopmostLoop(L);
1248   SE->forgetBlockAndLoopDispositions();
